import{_ as o,c as t,o as s,ag as n}from"./chunks/framework.DVUBUV_u.js";const u=JSON.parse('{"title":"Избранное","description":"","frontmatter":{"title":"Избранное"},"headers":[],"relativePath":"props/favorite.md","filePath":"props/favorite.md"}'),a={name:"props/favorite.md"};function e(i,r,l,g,p,h){return s(),t("div",null,[...r[0]||(r[0]=[n('<h1 id="избранное-props" tabindex="-1">Избранное (Props) <a class="header-anchor" href="#избранное-props" aria-label="Permalink to &quot;Избранное (Props)&quot;">​</a></h1><p><strong>Избранное</strong> в разделе <strong>Props</strong> — это сохраняемый список <strong>компонентов</strong>, к которым вы хотите быстро возвращаться между сессиями работы с инспектором. Отмеченные строки поднимаются <strong>ближе к началу</strong> таблицы, рядом с именем отображается <strong>звезда</strong>, а в шапке доступен счётчик найденных избранных на текущем экране.</p><p>Общее описание вкладки Props: <a href="/docs/props/general.html">Основные возможности</a>.</p><p><strong>Избранное для Pinia</strong> — отдельный список на вкладке <strong>Stores</strong> и в настройках <strong>Options → Pinia</strong>; здесь описаны только <strong>компоненты Vue</strong>.</p><hr><h2 id="где-добавить-и-убрать" tabindex="-1">Где добавить и убрать <a class="header-anchor" href="#где-добавить-и-убрать" aria-label="Permalink to &quot;Где добавить и убрать&quot;">​</a></h2><ul><li><strong>В таблице Props</strong> — клик по <strong>звезде</strong> у строки включает или выключает избранное для этого компонента (настройки сохраняются в хранилище инспектора).</li><li><strong>В карточке компонента</strong> (детальный просмотр) — такая же <strong>звезда</strong> в заголовке; логика та же.</li><li><strong>В Options</strong> — секция со списком избранных компонентов (<strong>Favorites</strong> в блоке настроек <strong>Props</strong>): просмотр сохранённых записей, удаление из списка, переход к выбранному элементу для редактирования деталей в боковой панели.</li></ul><p>После изменения избранного таблица обычно <strong>пересортировывается</strong>: отмеченные компоненты оказываются выше остальных (при совпадении с текущими фильтрами поиска).</p><hr><h2 id="что-именно-сохраняется" tabindex="-1">Что именно сохраняется <a class="header-anchor" href="#что-именно-сохраняется" aria-label="Permalink to &quot;Что именно сохраняется&quot;">​</a></h2><p>Для каждой записи хранится, среди прочего:</p><ul><li><strong>имя компонента</strong>;</li><li><strong>идентификатор</strong> для сопоставления с строкой в дереве (в том числе форма с привязкой к корневому DOM‑элементу: тег и классы);</li><li>при необходимости <strong>внутренний идентификатор узла</strong> текущей сессии (<strong>nodeId</strong>) — чтобы отличить два экземпляра с одинаковым именем и похожей разметкой;</li><li><strong>время добавления</strong> (для отображения в списке настроек).</li></ul><p>Так список может пережить <strong>перезагрузку страницы</strong>: после нового рендера инспектор снова пытается найти тот же компонент по сохранённым признакам.</p><hr><h2 id="как-выполняется-сопоставление" tabindex="-1">Как выполняется сопоставление <a class="header-anchor" href="#как-выполняется-сопоставление" aria-label="Permalink to &quot;Как выполняется сопоставление&quot;">​</a></h2><p>При открытии дерева и обновлении флагов «звезды» используется <strong>устойчивое сравнение</strong> идентификаторов:</p><ul><li>Если сохранён идентификатор в форме <strong>числового uid текущей сессии</strong>, совпадение возможно <strong>только пока живёт тот же экземпляр</strong> на странице (после полного пересоздания дерева uid меняется).</li><li>Для записей с <strong>именем компонента и сигнатурой корневого элемента</strong> (тег, классы и т.д.) сопоставление ориентируется на эти <strong>стабильные</strong> части, а не на случайный внутренний путь в дереве Vue.</li></ul><p>Для старых записей избранного, где в поле идентификатора остался только <strong>uid сессии</strong>, инспектор дополнительно может попробовать связать строку с деревом по <strong>сохранённым метаданным</strong> (имя, тег, класс), чтобы звезда снова загорелась после перезагрузки.</p><p>Если на странице появилось <strong>несколько</strong> подходящих кандидатов, может попасть не та строка, которую вы изначально имели в виду; в таких случаях помогает точнее заданное избранное (или снятие и повторное добавление уже с актуальным узлом).</p><hr><h2 id="счетчик-в-шапке" tabindex="-1">Счётчик в шапке <a class="header-anchor" href="#счетчик-в-шапке" aria-label="Permalink to &quot;Счётчик в шапке&quot;">​</a></h2><p>Рядом с полем поиска отображается бейдж вида <strong>«найдено / всего»</strong> избранных: сколько отмеченных компонентов <strong>видно</strong> с учётом текущего фильтра и сколько записей в списке избранного в настройках. Клик по бейджу может вести в <strong>Options</strong> на секцию избранного для правки списка (в интерфейсе это оформлено как быстрый переход к настройкам).</p><hr><h2 id="практические-советы" tabindex="-1">Практические советы <a class="header-anchor" href="#практические-советы" aria-label="Permalink to &quot;Практические советы&quot;">​</a></h2><ul><li>Используйте избранное для <strong>«якорных»</strong> экранов приложения: шапка, часто отлаживаемый виджет, проблемный фрагмент.</li><li>После <strong>крупных изменений вёрстки</strong> проверьте, что звезда всё ещё у нужного узла; при сбое сопоставления удалите запись и добавьте заново.</li><li>Избранное <strong>не влияет</strong> на рантайм приложения и не связано с <strong>чёрным списком</strong> компонентов — это независимые списки.</li></ul><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/props/general.html">Основные возможности Props</a></li><li><a href="/docs/props/blacklist.html">Чёрный список</a></li><li><a href="/docs/options/customize.html">Персонализация / настройки</a></li><li><a href="/docs/store/general.html">Основные возможности Store (Pinia)</a> — избранное по сторам задаётся отдельно</li></ul>',28)])])}const c=o(a,[["render",e]]);export{u as __pageData,c as default};
